#include <vector>
#include <algorithm>
#include <numeric>
using namespace std;

class DSU {
    vector<long long> parent;
    vector<long long> rank;
    long long numComponents;
public:
    DSU(long long n) {
        parent.resize(n);
        iota(parent.begin(), parent.end(), 0);
        rank.resize(n, 0);
        numComponents = n;
    }
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void unionSet(long long x, long long y) {
        x = find(x);
        y = find(y);
        if (x == y) return;
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else if (rank[x] > rank[y]) {
            parent[y] = x;
        } else {
            parent[y] = x;
            rank[x]++;
        }
        numComponents--;
    }
    long long components() const {
        return numComponents;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (edges.empty()) {
        if (n <= k) {
            return 0;
        } else {
            return 0;
        }
    }

    long long max_weight = 0;
    for (const auto& edge : edges) {
        if (edge[2] > max_weight) {
            max_weight = edge[2];
        }
    }

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    long long low = 0;
    long long high = max_weight;
    auto feasible = [n, &edges, k](long long x) {
        DSU dsu(n);
        for (const auto& edge : edges) {
            if (edge[2] > x) {
                break;
            }
            dsu.unionSet(edge[0], edge[1]);
        }
        return dsu.components() <= k;
    };

    while (low < high) {
        long long mid = low + (high - low) / 2;
        if (feasible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
```

